#include <bits/stdc++.h>
using namespace std;

int fnum[1000005], n, maxn = 0;
vector<int> p;

void make_prime() {
    for (int i = 2; i <= maxn; i++) {
        // printf("%2d has %2d prime factor(s)\n", i, fnum[i]);
        if (fnum[i] == 0) {
            fnum[i]++;
            p.push_back(i);
            // printf("  so %2d is a prime\n", i);
            for (int j = 2; i * j <= maxn; j++) {
                fnum[i * j]++;
                // printf("    fnum[%2d]++\n", i * j);
            }
        }
    }
}

int main() {
    cin >> n;
    int nums[10005];
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
        maxn = max(maxn, nums[i]);
    }
    make_prime();
    // for (int i = 2; i <= maxn; i++) {
    //     cout << i << ": " << fnum[i] << endl;
    // }
    for (int i = 0; i < n; i++) {
        cout << (fnum[nums[i]] == 2) << endl;
    }
    return 0;
}
